INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`) VALUES ('msg-fake-poly-0001', 'openai', 'User Input', 'ChatGPT', '2370-10-25T08:00:00.000000+00:00', 'user-FAKE0DATAANDROID0POSITRONIC1', 'user-FAKE0DATAANDROID0POSITRONIC1', NULL, NULL, 'Polynomial Fit for Sensor Calibration', '68fa0002-fake-7000-8000-positronic0002', 0, '/chat/68fa0002-fake-7000-8000-positronic0002', 'Fit a degree-2 polynomial to (1,2.1),(2,4.0),(3,9.1),(4,15.8),(5,25.0) in Python.', NULL);
INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`) VALUES ('msg-fake-poly-0002', 'openai', 'LLM Response', 'ChatGPT', '2370-10-25T08:03:20.000000+00:00', 'gpt-5', 'user-FAKE0DATAANDROID0POSITRONIC1', NULL, NULL, 'Polynomial Fit for Sensor Calibration', '68fa0002-fake-7000-8000-positronic0002', 1, '/chat/68fa0002-fake-7000-8000-positronic0002', 'import numpy as np\nx = np.array([1,2,3,4,5])\ny = np.array([2.1, 4.0, 9.1, 15.8, 25.0])\ncoeffs = np.polyfit(x, y, 2)\nprint(coeffs)\n', NULL);
INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`) VALUES ('msg-fake-poly-0003', 'openai', 'LLM Response', 'ChatGPT', '2370-10-25T08:05:20.000000+00:00', 'gpt-5', 'user-FAKE0DATAANDROID0POSITRONIC1', NULL, NULL, 'Polynomial Fit for Sensor Calibration', '68fa0002-fake-7000-8000-positronic0002', 2, '/chat/68fa0002-fake-7000-8000-positronic0002', 'The fit gives approximately y = 1.014 x² + 0.06 x + 1.07. R² ≈ 0.9997. The residuals suggest the underlying process is very close to pure quadratic with small measurement noise.', NULL);
INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`) VALUES ('msg-fake-spot-0000', 'openai', 'Tool Call', 'ChatGPT', '2370-10-24T08:00:00.000001+00:00', 'system', 'user-FAKE0DATAANDROID0POSITRONIC1', NULL, NULL, 'Sonnet on a Cat Named Spot', '68fa0001-fake-7000-8000-positronic0001', 0, '/chat/68fa0001-fake-7000-8000-positronic0001', 'User is Lt. Cmdr. Data, a sentient android. Prefers precise, literal language.', NULL);
INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`) VALUES ('msg-fake-spot-0001', 'openai', 'User Input', 'ChatGPT', '2370-10-24T08:00:00.000000+00:00', 'user-FAKE0DATAANDROID0POSITRONIC1', 'user-FAKE0DATAANDROID0POSITRONIC1', NULL, NULL, 'Sonnet on a Cat Named Spot', '68fa0001-fake-7000-8000-positronic0001', 1, '/chat/68fa0001-fake-7000-8000-positronic0001', 'Compose a Shakespearean sonnet about my cat Spot. Spot is an orange tabby with a fondness for jumping on consoles.', NULL);
INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`) VALUES ('msg-fake-spot-0002', 'openai', 'LLM Response', 'ChatGPT', '2370-10-24T08:02:00.000000+00:00', 'gpt-5', 'user-FAKE0DATAANDROID0POSITRONIC1', NULL, NULL, 'Sonnet on a Cat Named Spot', '68fa0001-fake-7000-8000-positronic0001', 2, '/chat/68fa0001-fake-7000-8000-positronic0001', 'Upon the bridge, where duty bids us stand,\nA tabby of the warmest tangerine,\nWith feline grace defies the captain''s hand\nAnd treads the helm with footfall light, serene.\n\nNo Klingon foe nor anomaly arrayed\nCan match the menace of his sudden leap;\nThe console glows where Spot in mirth has played,\nAnd alarms ring out where he chose to sleep.\n\nYet Data, faithful keeper, smiles unseen —\nAn android''s joy, though circuited and spare —\nFor in this beast a mystery serene\nReflects the very life he hopes to share.\n\nSo bless thee, Spot, of fur and quiet purr:\nThou art my muse, my console saboteur.', NULL);
INSERT INTO `grid_rows` (`uuid`, `provider`, `kind`, `source_label`, `when_ts`, `author`, `account`, `project`, `channel`, `conversation_name`, `conversation_uuid`, `message_index`, `entire_chat`, `text`, `slack_link`) VALUES ('msg-fake-spot-0003', 'openai', 'User Input', 'ChatGPT', '2370-10-24T08:05:00.000000+00:00', 'user-FAKE0DATAANDROID0POSITRONIC1', 'user-FAKE0DATAANDROID0POSITRONIC1', NULL, NULL, 'Sonnet on a Cat Named Spot', '68fa0001-fake-7000-8000-positronic0001', 3, '/chat/68fa0001-fake-7000-8000-positronic0001', 'Curious. The closing couplet is satisfying. Thank you.', NULL);
